    24→export function QuickAddModal({ isOpen, onClose, defaultColumn }: QuickAddModalProps) {
    25→  const { addTask, columns, getCardTemplates } = useKanbanStore();
    26→  const cardTemplates = getCardTemplates();
    27→
    28→  // Form state
    29→  const [title, setTitle] = useState('');
    30→  const [description, setDescription] = useState('');
    31→  const [column, setColumn] = useState(() => {
    32→    if (defaultColumn) return defaultColumn;
    33→    const saved = localStorage.getItem('kanban-quick-add-column');
    34→    return saved || 'todo';
    35→  });
    36→  const [priority, setPriority] = useState<TaskPriority>(() => {
    37→    const saved = localStorage.getItem('kanban-quick-add-priority');
    38→    return (saved as TaskPriority) || 'medium';
    39→  });
    40→  const [dueDate, setDueDate] = useState('');
    41→  const [tags, setTags] = useState<string[]>([]);
    42→  const [selectedTemplate, setSelectedTemplate] = useState<string | null>(null);
    43→
