    47→    if (!templateId) {
    48→      // Clear template-related fields but keep title
    49→      setDescription('');
    50→      setTags([]);
    51→      return;
    52→    }
    53→    const template = cardTemplates.find(t => t.id === templateId);
    54→    if (template) {
    55→      setDescription(template.description);
    56→      setPriority(template.defaultPriority);
    57→      setTags(template.defaultTags);
    58→      if (template.defaultColumn) {
    59→        setColumn(template.defaultColumn);
    60→      }
    61→    }
    62→  }, [cardTemplates]);
    63→
    64→  // Reset form when modal opens
    65→  useEffect(() => {
    66→    if (isOpen) {
    67→      setTitle('');
    68→      setDescription('');
    69→      setDueDate('');
    70→      setTags([]);
    71→      setSelectedTemplate(null);
    72→      // Keep column and priority (smart defaults)
    73→    }
    74→  }, [isOpen]);
    75→
    76→  // Save preferences when changed
    77→  useEffect(() => {
    78→    localStorage.setItem('kanban-quick-add-column', column);
    79→  }, [column]);
    80→
    81→  useEffect(() => {
    82→    localStorage.setItem('kanban-quick-add-priority', priority);
