   139→          exit={{ opacity: 0, scale: 0.95, y: -20 }}
   140→          className="relative w-full max-w-2xl mx-4 bg-surface-light dark:bg-surface-dark-elevated rounded-lg shadow-2xl border border-border-light dark:border-border-dark overflow-hidden max-h-[85vh] flex flex-col"
   141→        >
   142→          {/* Header */}
   143→          <div className="flex items-center justify-between px-4 py-3 border-b border-border-light dark:border-border-dark flex-shrink-0">
   144→            <div className="flex items-center gap-2">
   145→              <span className="text-base">⚡</span>
