   101→        {...attributes}
   102→        {...listeners}
   103→        className="cursor-grab active:cursor-grabbing text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary"
   104→        aria-label="Drag to reorder"
   105→      >
   106→        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
   107→          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8h16M4 16h16" />
   108→        </svg>
   109→      </button>
   110→
   111→      {/* Color indicator */}
   112→      <div className={`w-4 h-4 rounded-full ${column.color}`}></div>
   113→
   114→      {/* Column info */}
   115→      <div className="flex-1 min-w-0">
   116→        <div className="font-medium text-text-light-primary dark:text-text-dark-primary truncate">
   117→          {column.title}
   118→        </div>
   119→        {column.wipLimit && (
   120→          <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
   121→            WIP Limit: {column.wipLimit}
   122→          </div>
   123→        )}
   124→      </div>
   125→
   126→      {/* Actions */}
   127→      <div className="flex items-center gap-2">
   128→        <button
   129→          onClick={() => onEdit(column)}
   130→          className="p-1.5 text-text-light-secondary hover:text-accent-blue dark:text-text-dark-secondary dark:hover:text-accent-blue transition-colors"
   131→          aria-label="Edit column"
   132→        >
   133→          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
   134→            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
   135→          </svg>
   136→        </button>
   137→        <button
   138→          onClick={() => onDelete(column.id)}
   139→          className="p-1.5 text-text-light-secondary hover:text-status-error dark:text-text-dark-secondary dark:hover:text-status-error transition-colors"
   140→          aria-label="Delete column"
   141→        >
   142→          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
   143→            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
   144→          </svg>
   145→        </button>
   146→      </div>
   147→    </div>
   148→  );
   149→};
   150→
   151→/**
   152→ * ColumnManager Component
   153→ * Modal for managing Kanban columns (add, edit, delete, reorder, templates)
   154→ */
   155→export const ColumnManager: React.FC<ColumnManagerProps> = ({ isOpen, onClose, initialEditingColumnId }) => {
   156→  const { columns, addColumn, updateColumn, deleteColumn, reorderColumns, replaceAllColumns } = useKanbanStore();
   157→  const [editingColumn, setEditingColumn] = useState<KanbanColumn | null>(null);
   158→  const [showAddForm, setShowAddForm] = useState(false);
   159→  const [activeId, setActiveId] = useState<string | null>(null);
   160→
   161→  // Confirmation dialog state
   162→  const [pendingDeleteColumn, setPendingDeleteColumn] = useState<KanbanColumn | null>(null);
   163→  const [pendingTemplate, setPendingTemplate] = useState<keyof typeof TEMPLATES | null>(null);
   164→
   165→  // Error state
   166→  const [error, setError] = useState<string | null>(null);
   167→
   168→  // Form state
   169→  const [formData, setFormData] = useState({
   170→    title: '',
   171→    color: 'bg-status-info',
   172→    wipLimit: undefined as number | undefined,
   173→  });
   174→
   175→  // Auto-select column for editing when initialEditingColumnId is provided
   176→  useEffect(() => {
   177→    if (initialEditingColumnId && isOpen) {
   178→      const column = columns.find((col) => col.id === initialEditingColumnId);
   179→      if (column) {
   180→        handleEdit(column);
   181→      }
   182→    }
   183→  }, [initialEditingColumnId, isOpen, columns]);
   184→
   185→  // Drag sensors
   186→  const sensors = useSensors(
   187→    useSensor(PointerSensor, {
   188→      activationConstraint: {
   189→        distance: 8,
   190→      },
   191→    })
   192→  );
   193→
   194→  const handleDragStart = (event: DragStartEvent) => {
   195→    setActiveId(event.active.id as string);
   196→  };
   197→
   198→  const handleDragEnd = (event: DragEndEvent) => {
   199→    const { active, over } = event;
   200→    setActiveId(null);
   201→
   202→    if (over && active.id !== over.id) {
   203→      const oldIndex = columns.findIndex((col) => col.id === active.id);
   204→      const newIndex = columns.findIndex((col) => col.id === over.id);
   205→
   206→      const newOrder = [...columns];
   207→      const [moved] = newOrder.splice(oldIndex, 1);
   208→      newOrder.splice(newIndex, 0, moved);
   209→
   210→      reorderColumns(newOrder.map((col) => col.id));
   211→    }
   212→  };
   213→
   214→  const handleEdit = (column: KanbanColumn) => {
   215→    setEditingColumn(column);
   216→    setFormData({
   217→      title: column.title,
   218→      color: column.color,
   219→      wipLimit: column.wipLimit,
   220→    });
   221→    setShowAddForm(true);
   222→  };
   223→
   224→  const handleDelete = (id: string) => {
   225→    if (columns.length <= 1) {
   226→      setError('Cannot delete the last column. You must have at least one column.');
   227→      return;
   228→    }
   229→
   230→    const column = columns.find((col) => col.id === id);
   231→    if (column) {
   232→      setPendingDeleteColumn(column);
   233→    }
   234→  };
   235→
   236→  const confirmDelete = () => {
   237→    if (pendingDeleteColumn) {
   238→      deleteColumn(pendingDeleteColumn.id);
   239→      setPendingDeleteColumn(null);
   240→      setError(null);
   241→    }
   242→  };
   243→
   244→  const cancelDelete = () => {
   245→    setPendingDeleteColumn(null);
   246→  };
   247→
   248→  const handleSubmit = (e: React.FormEvent) => {
   249→    e.preventDefault();
   250→
   251→    if (!formData.title.trim()) return;
   252→
   253→    if (editingColumn) {
   254→      // Update existing column
   255→      updateColumn(editingColumn.id, {
   256→        title: formData.title.trim(),
   257→        color: formData.color,
   258→        wipLimit: formData.wipLimit || undefined,
   259→      });
   260→    } else {
   261→      // Add new column
   262→      addColumn({
   263→        title: formData.title.trim(),
   264→        color: formData.color,
   265→        wipLimit: formData.wipLimit || undefined,
   266→      });
   267→    }
   268→
   269→    // Reset form
   270→    setFormData({ title: '', color: 'bg-status-info', wipLimit: undefined });
   271→    setEditingColumn(null);
   272→    setShowAddForm(false);
   273→  };
   274→
   275→  const handleCancel = () => {
   276→    setFormData({ title: '', color: 'bg-status-info', wipLimit: undefined });
   277→    setEditingColumn(null);
   278→    setShowAddForm(false);
   279→  };
   280→
   281→  const applyTemplate = (templateKey: keyof typeof TEMPLATES) => {
   282→    setPendingTemplate(templateKey);
   283→  };
   284→
   285→  const confirmTemplate = () => {
   286→    if (pendingTemplate) {
   287→      // Use atomic replace to avoid race condition
   288→      replaceAllColumns(TEMPLATES[pendingTemplate]);
   289→
   290→      setPendingTemplate(null);
   291→      setError(null);
   292→    }
   293→  };
   294→
   295→  const cancelTemplate = () => {
   296→    setPendingTemplate(null);
   297→  };
   298→
   299→  const activeColumn = columns.find((col) => col.id === activeId);
   300→
   301→  return (
   302→    <Modal isOpen={isOpen} onClose={onClose} title="Manage Columns" maxWidth="lg">
   303→      <div className="space-y-6">
   304→        {/* Templates */}
   305→        <div>
   306→          <h4 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">
   307→            Templates
   308→          </h4>
   309→          <div className="grid grid-cols-3 gap-2">
   310→            <button
   311→              onClick={() => applyTemplate('dev')}
   312→              className="px-3 py-2 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg hover:border-accent-blue transition-colors text-text-light-primary dark:text-text-dark-primary"
   313→            >
   314→              Development
   315→            </button>
   316→            <button
   317→              onClick={() => applyTemplate('pm')}
   318→              className="px-3 py-2 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg hover:border-accent-blue transition-colors text-text-light-primary dark:text-text-dark-primary"
   319→            >
   320→              Project Management
   321→            </button>
   322→            <button
   323→              onClick={() => applyTemplate('marketing')}
   324→              className="px-3 py-2 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg hover:border-accent-blue transition-colors text-text-light-primary dark:text-text-dark-primary"
   325→            >
   326→              Marketing
   327→            </button>
   328→          </div>
   329→        </div>
   330→
   331→        {/* Column List */}
   332→        <div>
   333→          <div className="flex items-center justify-between mb-3">
   334→            <h4 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">
   335→              Columns ({columns.length})
   336→            </h4>
   337→            {!showAddForm && (
   338→              <button
   339→                onClick={() => setShowAddForm(true)}
   340→                className="text-sm text-accent-blue hover:text-accent-blue-hover"
   341→              >
   342→                + Add Column
   343→              </button>
   344→            )}
   345→          </div>
   346→
   347→          {/* Add/Edit Form */}
   348→          {showAddForm && (
   349→            <form onSubmit={handleSubmit} className="mb-4 p-4 bg-surface-light dark:bg-surface-dark rounded-lg border-2 border-accent-blue space-y-3">
   350→              <div>
   351→                <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
   352→                  Column Name
   353→                </label>
   354→                <input
   355→                  type="text"
   356→                  value={formData.title}
   357→                  onChange={(e) => setFormData({ ...formData, title: e.target.value })}
   358→                  placeholder="e.g., In Progress"
   359→                  className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue focus:outline-none"
   360→                  autoFocus
   361→                />
   362→              </div>
   363→
   364→              <div>
   365→                <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
   366→                  Color
   367→                </label>
   368→                <div className="flex gap-2 flex-wrap">
   369→                  {COLOR_OPTIONS.map((option) => (
   370→                    <button
   371→                      key={option.class}
   372→                      type="button"
   373→                      onClick={() => setFormData({ ...formData, color: option.class })}
   374→                      className={`w-8 h-8 rounded-full ${option.preview} ${
   375→                        formData.color === option.class
   376→                          ? 'ring-2 ring-accent-blue ring-offset-2 ring-offset-surface-light dark:ring-offset-surface-dark'
   377→                          : ''
   378→                      }`}
   379→                      title={option.label}
   380→                    />
   381→                  ))}
   382→                </div>
   383→              </div>
   384→
   385→              <div>
   386→                <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
   387→                  WIP Limit (Optional)
   388→                </label>
   389→                <input
   390→                  type="number"
   391→                  value={formData.wipLimit || ''}
   392→                  onChange={(e) =>
   393→                    setFormData({
   394→                      ...formData,
   395→                      wipLimit: e.target.value ? parseInt(e.target.value) : undefined,
   396→                    })
   397→                  }
   398→                  placeholder="e.g., 5"
   399→                  min="1"
   400→                  className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue focus:outline-none"
   401→                />
   402→                <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
   403→                  Maximum number of tasks allowed in this column
   404→                </p>
   405→              </div>
   406→
   407→              <div className="flex gap-2">
   408→                <button
   409→                  type="submit"
   410→                  className="flex-1 px-4 py-2 text-sm bg-accent-blue text-white rounded-lg hover:bg-accent-blue-hover transition-colors"
   411→                >
   412→                  {editingColumn ? 'Update Column' : 'Add Column'}
   413→                </button>
   414→                <button
   415→                  type="button"
   416→                  onClick={handleCancel}
   417→                  className="px-4 py-2 text-sm bg-neutral-600 text-white rounded-lg hover:opacity-80 transition-opacity"
   418→                >
   419→                  Cancel
   420→                </button>
   421→              </div>
   422→            </form>
   423→          )}
   424→
   425→          {/* Sortable Column List */}
   426→          <DndContext
   427→            sensors={sensors}
   428→            collisionDetection={closestCenter}
   429→            onDragStart={handleDragStart}
   430→            onDragEnd={handleDragEnd}
   431→          >
   432→            <SortableContext items={columns.map((col) => col.id)} strategy={verticalListSortingStrategy}>
   433→              <div className="space-y-2">
   434→                {columns.map((column) => (
   435→                  <SortableColumnItem
   436→                    key={column.id}
   437→                    column={column}
   438→                    onEdit={handleEdit}
   439→                    onDelete={handleDelete}
   440→                  />
   441→                ))}
   442→              </div>
   443→            </SortableContext>
   444→
   445→            <DragOverlay>
   446→              {activeColumn && (
   447→                <div className="flex items-center gap-3 p-3 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg border border-border-light dark:border-border-dark shadow-lg">
   448→                  <div className={`w-4 h-4 rounded-full ${activeColumn.color}`}></div>
   449→                  <div className="font-medium text-text-light-primary dark:text-text-dark-primary">
   450→                    {activeColumn.title}
   451→                  </div>
   452→                </div>
   453→              )}
   454→            </DragOverlay>
   455→          </DndContext>
   456→        </div>
   457→
   458→        {/* Error Message */}
   459→        {error && (
   460→          <div className="p-3 bg-status-error/10 border border-status-error rounded-lg text-status-error text-sm">
   461→            {error}
   462→          </div>
   463→        )}
   464→
   465→        {/* Help Text */}
   466→        <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary bg-surface-light-elevated dark:bg-surface-dark-elevated p-3 rounded-lg">
   467→          <p className="font-medium mb-1">Tips:</p>
   468→          <ul className="space-y-1 list-disc list-inside">
   469→            <li>Drag columns to reorder them on the board</li>
   470→            <li>Set WIP limits to prevent overload in any column</li>
   471→            <li>Deleting a column moves all tasks to Backlog</li>
   472→            <li>Templates replace all current columns</li>
   473→          </ul>
   474→        </div>
   475→      </div>
   476→
   477→      {/* Delete Confirmation Dialog */}
   478→      {pendingDeleteColumn && (
   479→        <ConfirmDialog
   480→          isOpen={true}
   481→          onClose={cancelDelete}
   482→          onConfirm={confirmDelete}
   483→          title="Delete Column"
   484→          message={`Are you sure you want to delete "${pendingDeleteColumn.title}"? All tasks in this column will be moved to Backlog.`}
   485→          confirmText="Delete"
   486→          cancelText="Cancel"
   487→          variant="danger"
   488→        />
   489→      )}
   490→
   491→      {/* Template Confirmation Dialog */}
   492→      {pendingTemplate && (
   493→        <ConfirmDialog
   494→          isOpen={true}
   495→          onClose={cancelTemplate}
   496→          onConfirm={confirmTemplate}
   497→          title="Apply Template"
   498→          message={`This will replace all current columns with the ${pendingTemplate === 'dev' ? 'Development' : pendingTemplate === 'pm' ? 'Project Management' : 'Marketing'} template. This action cannot be undone.`}
   499→          confirmText="Apply Template"
   500→          cancelText="Cancel"
   501→          variant="warning"
   502→        />
   503→      )}
   504→    </Modal>
   505→  );
   506→};
