import { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useKanbanStore } from '../../stores/useKanbanStore';
import { useEscapeKey } from '../../hooks/useEscapeKey';
import { NaturalLanguageDateInput } from '../../components/NaturalLanguageDateInput';
import type { TaskPriority } from '../../types';

interface QuickAddModalProps {
  isOpen: boolean;
  onClose: () => void;
  defaultColumn?: string;
}

/**
 * QuickAddModal - Quick task creation with Cmd/Ctrl+K
 * Phase A: Quick Wins - Quick Add Feature
 *
 * Features:
 * - Keyboard-first design (Cmd/Ctrl+K to open)
 * - Smart defaults (remembers last used column and priority)
 * - Minimal UI (title + optional details)
 * - Instant creation (no detail panel needed)
 */
export function QuickAddModal({ isOpen, onClose, defaultColumn }: QuickAddModalProps) {
  const { addTask, columns, getCardTemplates } = useKanbanStore();
  const cardTemplates = getCardTemplates();

  // Form state
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [column, setColumn] = useState(() => {
    if (defaultColumn) return defaultColumn;
    const saved = localStorage.getItem('kanban-quick-add-column');
    return saved || 'todo';
  });
  const [priority, setPriority] = useState<TaskPriority>(() => {
    const saved = localStorage.getItem('kanban-quick-add-priority');
    return (saved as TaskPriority) || 'medium';
  });
  const [dueDate, setDueDate] = useState('');
  const [tags, setTags] = useState<string[]>([]);
  const [selectedTemplate, setSelectedTemplate] = useState<string | null>(null);

  // Apply template when selected
  const applyTemplate = useCallback((templateId: string | null) => {
    setSelectedTemplate(templateId);
    if (!templateId) {
      // Clear template-related fields but keep title
      setDescription('');
      setTags([]);
      return;
    }
    const template = cardTemplates.find(t => t.id === templateId);
    if (template) {
      setDescription(template.description);
      setPriority(template.defaultPriority);
      setTags(template.defaultTags);
      if (template.defaultColumn) {
        setColumn(template.defaultColumn);
      }
    }
  }, [cardTemplates]);

  // Reset form when modal opens
  useEffect(() => {
    if (isOpen) {
      setTitle('');
      setDescription('');
      setDueDate('');
      setTags([]);
      setSelectedTemplate(null);
      // Keep column and priority (smart defaults)
    }
  }, [isOpen]);

  // Save preferences when changed
  useEffect(() => {
    localStorage.setItem('kanban-quick-add-column', column);
  }, [column]);

  useEffect(() => {
    localStorage.setItem('kanban-quick-add-priority', priority);
  }, [priority]);

  // Handle ESC key with priority 50 (z-50)
  useEscapeKey({ enabled: isOpen, onEscape: onClose, priority: 50 });

  // Keyboard shortcuts (Cmd+Enter to submit)
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (!isOpen) return;

      // Cmd/Ctrl+Enter to submit
      if ((e.metaKey || e.ctrlKey) && e.key === 'Enter') {
        e.preventDefault();
        handleSubmit();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isOpen, title, column, priority, description, dueDate]);

  const handleSubmit = useCallback(() => {
    if (!title.trim()) return;

    addTask({
      title: title.trim(),
      description: description.trim(),
      status: column as any,
      priority,
      startDate: null,
      dueDate: dueDate || null,
      tags,
      projectIds: [],
    });

    onClose();
  }, [title, description, column, priority, dueDate, tags, addTask, onClose]);

  if (!isOpen) return null;

  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-50 flex items-start justify-center pt-20">
        {/* Backdrop */}
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="absolute inset-0 bg-black/50"
          onClick={onClose}
        />

        {/* Modal */}
        <motion.div
          initial={{ opacity: 0, scale: 0.95, y: -20 }}
          animate={{ opacity: 1, scale: 1, y: 0 }}
          exit={{ opacity: 0, scale: 0.95, y: -20 }}
          className="relative w-full max-w-2xl mx-4 bg-surface-light dark:bg-surface-dark-elevated rounded-lg shadow-2xl border border-border-light dark:border-border-dark overflow-hidden max-h-[85vh] flex flex-col"
        >
          {/* Header */}
          <div className="flex items-center justify-between px-4 py-3 border-b border-border-light dark:border-border-dark flex-shrink-0">
            <div className="flex items-center gap-2">
              <span className="text-base">⚡</span>
              <h2 className="text-base font-semibold text-text-light-primary dark:text-text-dark-primary">
                Quick Add Task
              </h2>
            </div>
            <button
              onClick={onClose}
              className="p-1.5 rounded-lg hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
              aria-label="Close"
            >
              <span className="text-lg text-text-light-secondary dark:text-text-dark-secondary">×</span>
            </button>
          </div>

          {/* Form */}
          <div className="p-4 space-y-3 flex-1 overflow-y-auto">
            {/* Template Selector */}
            <div>
              <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5">
                Template (optional)
              </label>
              <div className="flex flex-wrap gap-1.5">
                <button
                  type="button"
                  onClick={() => applyTemplate(null)}
                  className={`px-2.5 py-1 text-xs rounded-lg border transition-colors ${
                    selectedTemplate === null
                      ? 'bg-accent-blue text-white border-accent-blue'
                      : 'border-border-light dark:border-border-dark text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-neutral-800'
                  }`}
                >
                  Blank
                </button>
                {cardTemplates.map((template) => (
                  <button
                    key={template.id}
                    type="button"
                    onClick={() => applyTemplate(template.id)}
                    className={`px-2.5 py-1 text-xs rounded-lg border transition-colors ${
                      selectedTemplate === template.id
                        ? 'bg-accent-blue text-white border-accent-blue'
                        : 'border-border-light dark:border-border-dark text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated'
                    }`}
                    title={template.name}
                  >
                    {template.icon} {template.name}
                  </button>
                ))}
              </div>
            </div>

            {/* Title (auto-focused) */}
            <div>
              <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5">
                Task Title *
              </label>
              <input
                type="text"
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                placeholder="What needs to be done?"
                className="w-full px-2.5 py-1.5 text-xs border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary placeholder:text-text-light-secondary dark:placeholder:text-text-dark-secondary focus:outline-none focus:ring-2 focus:ring-accent-blue"
                autoFocus
              />
            </div>

            {/* Row 1: Column + Priority */}
            <div className="grid grid-cols-2 gap-2">
              <div>
                <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5">
                  Column
                </label>
                <select
                  value={column}
                  onChange={(e) => setColumn(e.target.value)}
                  className="w-full px-2.5 py-1.5 text-xs border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-blue"
                >
                  {columns.map((col) => (
                    <option key={col.id} value={col.id}>
                      {col.title}
                    </option>
                  ))}
                </select>
              </div>

              <div>
                <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5">
                  Priority
                </label>
                <select
                  value={priority}
                  onChange={(e) => setPriority(e.target.value as TaskPriority)}
                  className="w-full px-2.5 py-1.5 text-xs border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-blue"
                >
                  <option value="low">Low</option>
                  <option value="medium">Medium</option>
                  <option value="high">High</option>
                </select>
              </div>
            </div>

            {/* Row 2: Due Date (Natural Language) */}
            <div>
              <NaturalLanguageDateInput
                value={dueDate}
                onChange={(date) => setDueDate(date || '')}
                label="Due Date (optional)"
                placeholder="Type 'tomorrow', 'next Friday', 'in 2 weeks'..."
              />
            </div>

            {/* Description (optional, collapsible) */}
            <div>
              <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5">
                Description (optional)
              </label>
              <textarea
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                placeholder="Add more details..."
                rows={2}
                className="w-full px-2.5 py-1.5 text-xs border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary placeholder:text-text-light-secondary dark:placeholder:text-text-dark-secondary focus:outline-none focus:ring-2 focus:ring-accent-blue resize-none"
              />
            </div>

            {/* Tags (from template) */}
            {tags.length > 0 && (
              <div>
                <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5">
                  Tags
                </label>
                <div className="flex flex-wrap gap-1.5">
                  {tags.map((tag) => (
                    <span
                      key={tag}
                      className="px-2 py-0.5 text-[10px] font-medium bg-accent-blue/10 text-accent-blue rounded-full"
                    >
                      {tag}
                    </span>
                  ))}
                </div>
              </div>
            )}
          </div>

          {/* Footer */}
          <div className="px-4 py-3 bg-surface-light-elevated dark:bg-surface-dark border-t border-border-light dark:border-border-dark flex items-center justify-between flex-shrink-0">
            <div className="text-[10px] text-text-light-secondary dark:text-text-dark-secondary">
              <kbd className="px-1.5 py-0.5 text-[10px] font-mono bg-surface-light-elevated dark:bg-surface-dark-elevated rounded border border-border-light dark:border-border-dark">
                ⌘
              </kbd>
              {' + '}
              <kbd className="px-1.5 py-0.5 text-[10px] font-mono bg-surface-light-elevated dark:bg-surface-dark-elevated rounded border border-border-light dark:border-border-dark">
                Enter
              </kbd>
              {' '}to create
            </div>
            <div className="flex gap-2">
              <button
                onClick={onClose}
                className="px-3 py-1.5 text-xs font-medium bg-surface-light dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary rounded-lg border border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleSubmit}
                disabled={!title.trim()}
                className="px-3 py-1.5 text-xs font-medium bg-accent-blue text-white rounded-lg hover:bg-accent-blue-hover transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
              >
                Create Task
              </button>
            </div>
          </div>
        </motion.div>
      </div>
    </AnimatePresence>
  );
}

import React, { useState, useEffect } from 'react';
import {
  DndContext,
  DragOverlay,
  PointerSensor,
  useSensor,
  useSensors,
  closestCenter,
  type DragEndEvent,
  type DragStartEvent,
} from '@dnd-kit/core';
import {
  SortableContext,
  verticalListSortingStrategy,
  useSortable,
} from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import { Modal } from '../../components/Modal';
import { ConfirmDialog } from '../../components/ConfirmDialog';
import { useKanbanStore } from '../../stores/useKanbanStore';
import type { KanbanColumn } from '../../types';

interface ColumnManagerProps {
  isOpen: boolean;
  onClose: () => void;
  initialEditingColumnId?: string; // NEW: Pre-select column for editing
}

// Predefined color options for columns
const COLOR_OPTIONS = [
  { label: 'Gray', class: 'bg-text-light-secondary dark:bg-text-dark-secondary', preview: 'bg-text-light-secondary dark:bg-text-dark-secondary' },
  { label: 'Blue', class: 'bg-status-info', preview: 'bg-accent-blue' },
  { label: 'Yellow', class: 'bg-status-warning', preview: 'bg-accent-yellow' },
  { label: 'Cyan', class: 'bg-accent-blue', preview: 'bg-accent-cyan' },
  { label: 'Green', class: 'bg-status-success', preview: 'bg-accent-green' },
  { label: 'Red', class: 'bg-status-error', preview: 'bg-accent-red' },
  { label: 'Magenta', class: 'bg-accent-magenta', preview: 'bg-accent-magenta' },
];

// Column templates
const TEMPLATES = {
  dev: [
    { title: 'Backlog', color: 'bg-text-light-secondary dark:bg-text-dark-secondary' },
    { title: 'To Do', color: 'bg-status-info' },
    { title: 'In Progress', color: 'bg-status-warning' },
    { title: 'In Review', color: 'bg-accent-blue' },
    { title: 'Done', color: 'bg-status-success' },
  ],
  pm: [
    { title: 'Ideas', color: 'bg-text-light-secondary dark:bg-text-dark-secondary' },
    { title: 'Planned', color: 'bg-status-info' },
    { title: 'Active', color: 'bg-status-warning' },
    { title: 'Blocked', color: 'bg-status-error' },
    { title: 'Complete', color: 'bg-status-success' },
  ],
  marketing: [
    { title: 'Ideation', color: 'bg-text-light-secondary dark:bg-text-dark-secondary' },
    { title: 'Draft', color: 'bg-status-info' },
    { title: 'Review', color: 'bg-status-warning' },
    { title: 'Scheduled', color: 'bg-accent-blue' },
    { title: 'Published', color: 'bg-status-success' },
  ],
};

// Sortable column item
interface SortableColumnItemProps {
  column: KanbanColumn;
  onEdit: (column: KanbanColumn) => void;
  onDelete: (id: string) => void;
}

const SortableColumnItem: React.FC<SortableColumnItemProps> = ({
  column,
  onEdit,
  onDelete,
}) => {
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({ id: column.id });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
  };

  return (
    <div
      ref={setNodeRef}
      style={style}
      className={`flex items-center gap-3 p-3 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg border border-border-light dark:border-border-dark ${
        isDragging ? 'opacity-50' : ''
      }`}
    >
      {/* Drag handle */}
      <button
        {...attributes}
        {...listeners}
        className="cursor-grab active:cursor-grabbing text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary"
        aria-label="Drag to reorder"
      >
        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8h16M4 16h16" />
        </svg>
      </button>

      {/* Color indicator */}
      <div className={`w-4 h-4 rounded-full ${column.color}`}></div>

      {/* Column info */}
      <div className="flex-1 min-w-0">
        <div className="font-medium text-text-light-primary dark:text-text-dark-primary truncate">
          {column.title}
        </div>
        {column.wipLimit && (
          <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
            WIP Limit: {column.wipLimit}
          </div>
        )}
      </div>

      {/* Actions */}
      <div className="flex items-center gap-2">
        <button
          onClick={() => onEdit(column)}
          className="p-1.5 text-text-light-secondary hover:text-accent-blue dark:text-text-dark-secondary dark:hover:text-accent-blue transition-colors"
          aria-label="Edit column"
        >
          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
          </svg>
        </button>
        <button
          onClick={() => onDelete(column.id)}
          className="p-1.5 text-text-light-secondary hover:text-status-error dark:text-text-dark-secondary dark:hover:text-status-error transition-colors"
          aria-label="Delete column"
        >
          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
          </svg>
        </button>
      </div>
    </div>
  );
};

/**
 * ColumnManager Component
 * Modal for managing Kanban columns (add, edit, delete, reorder, templates)
 */
export const ColumnManager: React.FC<ColumnManagerProps> = ({ isOpen, onClose, initialEditingColumnId }) => {
  const { columns, addColumn, updateColumn, deleteColumn, reorderColumns, replaceAllColumns } = useKanbanStore();
  const [editingColumn, setEditingColumn] = useState<KanbanColumn | null>(null);
  const [showAddForm, setShowAddForm] = useState(false);
  const [activeId, setActiveId] = useState<string | null>(null);

  // Confirmation dialog state
  const [pendingDeleteColumn, setPendingDeleteColumn] = useState<KanbanColumn | null>(null);
  const [pendingTemplate, setPendingTemplate] = useState<keyof typeof TEMPLATES | null>(null);

  // Error state
  const [error, setError] = useState<string | null>(null);

  // Form state
  const [formData, setFormData] = useState({
    title: '',
    color: 'bg-status-info',
    wipLimit: undefined as number | undefined,
  });

  // Auto-select column for editing when initialEditingColumnId is provided
  useEffect(() => {
    if (initialEditingColumnId && isOpen) {
      const column = columns.find((col) => col.id === initialEditingColumnId);
      if (column) {
        handleEdit(column);
      }
    }
  }, [initialEditingColumnId, isOpen, columns]);

  // Drag sensors
  const sensors = useSensors(
    useSensor(PointerSensor, {
      activationConstraint: {
        distance: 8,
      },
    })
  );

  const handleDragStart = (event: DragStartEvent) => {
    setActiveId(event.active.id as string);
  };

  const handleDragEnd = (event: DragEndEvent) => {
    const { active, over } = event;
    setActiveId(null);

    if (over && active.id !== over.id) {
      const oldIndex = columns.findIndex((col) => col.id === active.id);
      const newIndex = columns.findIndex((col) => col.id === over.id);

      const newOrder = [...columns];
      const [moved] = newOrder.splice(oldIndex, 1);
      newOrder.splice(newIndex, 0, moved);

      reorderColumns(newOrder.map((col) => col.id));
    }
  };

  const handleEdit = (column: KanbanColumn) => {
    setEditingColumn(column);
    setFormData({
      title: column.title,
      color: column.color,
      wipLimit: column.wipLimit,
    });
    setShowAddForm(true);
  };

  const handleDelete = (id: string) => {
    if (columns.length <= 1) {
      setError('Cannot delete the last column. You must have at least one column.');
      return;
    }

    const column = columns.find((col) => col.id === id);
    if (column) {
      setPendingDeleteColumn(column);
    }
  };

  const confirmDelete = () => {
    if (pendingDeleteColumn) {
      deleteColumn(pendingDeleteColumn.id);
      setPendingDeleteColumn(null);
      setError(null);
    }
  };

  const cancelDelete = () => {
    setPendingDeleteColumn(null);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.title.trim()) return;

    if (editingColumn) {
      // Update existing column
      updateColumn(editingColumn.id, {
        title: formData.title.trim(),
        color: formData.color,
        wipLimit: formData.wipLimit || undefined,
      });
    } else {
      // Add new column
      addColumn({
        title: formData.title.trim(),
        color: formData.color,
        wipLimit: formData.wipLimit || undefined,
      });
    }

    // Reset form
    setFormData({ title: '', color: 'bg-status-info', wipLimit: undefined });
    setEditingColumn(null);
    setShowAddForm(false);
  };

  const handleCancel = () => {
    setFormData({ title: '', color: 'bg-status-info', wipLimit: undefined });
    setEditingColumn(null);
    setShowAddForm(false);
  };

  const applyTemplate = (templateKey: keyof typeof TEMPLATES) => {
    setPendingTemplate(templateKey);
  };

  const confirmTemplate = () => {
    if (pendingTemplate) {
      // Use atomic replace to avoid race condition
      replaceAllColumns(TEMPLATES[pendingTemplate]);

      setPendingTemplate(null);
      setError(null);
    }
  };

  const cancelTemplate = () => {
    setPendingTemplate(null);
  };

  const activeColumn = columns.find((col) => col.id === activeId);

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="Manage Columns" maxWidth="lg">
      <div className="space-y-6">
        {/* Templates */}
        <div>
          <h4 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary mb-3">
            Templates
          </h4>
          <div className="grid grid-cols-3 gap-2">
            <button
              onClick={() => applyTemplate('dev')}
              className="px-3 py-2 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg hover:border-accent-blue transition-colors text-text-light-primary dark:text-text-dark-primary"
            >
              Development
            </button>
            <button
              onClick={() => applyTemplate('pm')}
              className="px-3 py-2 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg hover:border-accent-blue transition-colors text-text-light-primary dark:text-text-dark-primary"
            >
              Project Management
            </button>
            <button
              onClick={() => applyTemplate('marketing')}
              className="px-3 py-2 text-sm bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-lg hover:border-accent-blue transition-colors text-text-light-primary dark:text-text-dark-primary"
            >
              Marketing
            </button>
          </div>
        </div>

        {/* Column List */}
        <div>
          <div className="flex items-center justify-between mb-3">
            <h4 className="text-sm font-semibold text-text-light-primary dark:text-text-dark-primary">
              Columns ({columns.length})
            </h4>
            {!showAddForm && (
              <button
                onClick={() => setShowAddForm(true)}
                className="text-sm text-accent-blue hover:text-accent-blue-hover"
              >
                + Add Column
              </button>
            )}
          </div>

          {/* Add/Edit Form */}
          {showAddForm && (
            <form onSubmit={handleSubmit} className="mb-4 p-4 bg-surface-light dark:bg-surface-dark rounded-lg border-2 border-accent-blue space-y-3">
              <div>
                <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
                  Column Name
                </label>
                <input
                  type="text"
                  value={formData.title}
                  onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                  placeholder="e.g., In Progress"
                  className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue focus:outline-none"
                  autoFocus
                />
              </div>

              <div>
                <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
                  Color
                </label>
                <div className="flex gap-2 flex-wrap">
                  {COLOR_OPTIONS.map((option) => (
                    <button
                      key={option.class}
                      type="button"
                      onClick={() => setFormData({ ...formData, color: option.class })}
                      className={`w-8 h-8 rounded-full ${option.preview} ${
                        formData.color === option.class
                          ? 'ring-2 ring-accent-blue ring-offset-2 ring-offset-surface-light dark:ring-offset-surface-dark'
                          : ''
                      }`}
                      title={option.label}
                    />
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
                  WIP Limit (Optional)
                </label>
                <input
                  type="number"
                  value={formData.wipLimit || ''}
                  onChange={(e) =>
                    setFormData({
                      ...formData,
                      wipLimit: e.target.value ? parseInt(e.target.value) : undefined,
                    })
                  }
                  placeholder="e.g., 5"
                  min="1"
                  className="w-full px-3 py-2 text-sm border border-border-light dark:border-border-dark rounded bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue focus:outline-none"
                />
                <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
                  Maximum number of tasks allowed in this column
                </p>
              </div>

              <div className="flex gap-2">
                <button
                  type="submit"
                  className="flex-1 px-4 py-2 text-sm bg-accent-blue text-white rounded-lg hover:bg-accent-blue-hover transition-colors"
                >
                  {editingColumn ? 'Update Column' : 'Add Column'}
                </button>
                <button
                  type="button"
                  onClick={handleCancel}
                  className="px-4 py-2 text-sm bg-neutral-600 text-white rounded-lg hover:opacity-80 transition-opacity"
                >
                  Cancel
                </button>
              </div>
            </form>
          )}

          {/* Sortable Column List */}
          <DndContext
            sensors={sensors}
            collisionDetection={closestCenter}
            onDragStart={handleDragStart}
            onDragEnd={handleDragEnd}
          >
            <SortableContext items={columns.map((col) => col.id)} strategy={verticalListSortingStrategy}>
              <div className="space-y-2">
                {columns.map((column) => (
                  <SortableColumnItem
                    key={column.id}
                    column={column}
                    onEdit={handleEdit}
                    onDelete={handleDelete}
                  />
                ))}
              </div>
            </SortableContext>

            <DragOverlay>
              {activeColumn && (
                <div className="flex items-center gap-3 p-3 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg border border-border-light dark:border-border-dark shadow-lg">
                  <div className={`w-4 h-4 rounded-full ${activeColumn.color}`}></div>
                  <div className="font-medium text-text-light-primary dark:text-text-dark-primary">
                    {activeColumn.title}
                  </div>
                </div>
              )}
            </DragOverlay>
          </DndContext>
        </div>

        {/* Error Message */}
        {error && (
          <div className="p-3 bg-status-error/10 border border-status-error rounded-lg text-status-error text-sm">
            {error}
          </div>
        )}

        {/* Help Text */}
        <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary bg-surface-light-elevated dark:bg-surface-dark-elevated p-3 rounded-lg">
          <p className="font-medium mb-1">Tips:</p>
          <ul className="space-y-1 list-disc list-inside">
            <li>Drag columns to reorder them on the board</li>
            <li>Set WIP limits to prevent overload in any column</li>
            <li>Deleting a column moves all tasks to Backlog</li>
            <li>Templates replace all current columns</li>
          </ul>
        </div>
      </div>

      {/* Delete Confirmation Dialog */}
      {pendingDeleteColumn && (
        <ConfirmDialog
          isOpen={true}
          onClose={cancelDelete}
          onConfirm={confirmDelete}
          title="Delete Column"
          message={`Are you sure you want to delete "${pendingDeleteColumn.title}"? All tasks in this column will be moved to Backlog.`}
          confirmText="Delete"
          cancelText="Cancel"
          variant="danger"
        />
      )}

      {/* Template Confirmation Dialog */}
      {pendingTemplate && (
        <ConfirmDialog
          isOpen={true}
          onClose={cancelTemplate}
          onConfirm={confirmTemplate}
          title="Apply Template"
          message={`This will replace all current columns with the ${pendingTemplate === 'dev' ? 'Development' : pendingTemplate === 'pm' ? 'Project Management' : 'Marketing'} template. This action cannot be undone.`}
          confirmText="Apply Template"
          cancelText="Cancel"
          variant="warning"
        />
      )}
    </Modal>
  );
};

